import{_ as t,o,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Google Marketing Platform Overview","description":"","frontmatter":{"title":"Google Marketing Platform Overview","slug":"google-marketing-platform"},"headers":[],"relativePath":"marketer-hub/google-marketing-platform.md","filePath":"marketer-hub/google-marketing-platform.md"}'),d={name:"marketer-hub/google-marketing-platform.md"};function i(n,e,s,c,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch connects to Google Marketing Platform (GMP) to surface ad-drive app conversions in the Branch Dashboard.</p><p>Google Marketing Platform includes the following products:</p><ul><li><p>Display &amp; Video 360 (DV360)</p><ul><li>Formerly DoubleClick Bid Manager (DBM)</li></ul></li><li><p>Campaign Manager 360 (CM360)</p><ul><li>Formerly DoubleClick Campaign Manager (DCM)</li></ul></li></ul><p><strong>Important</strong>: Please use the GMP integration in the Branch Dashboard instead of DoubleClick, which is the legacy integration.</p><h3 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h3><p>By connecting your GMP and Branch accounts, you can:</p><ul><li>Send app conversion data collected by the Branch SDK to GMP for attribution.</li><li>Gain <code>read-only</code> access to app conversion data from GMP Ads in your Branch Dashboard. <strong>This does not include cost/click/impression data</strong>.</li></ul><h3 id="feature-support" tabindex="-1">Feature Support <a class="header-anchor" href="#feature-support" aria-label="Permalink to &quot;Feature Support&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Supported</th></tr></thead><tbody><tr><td>View-Through Attribution</td><td><strong>Yes</strong></td></tr><tr><td>Click-Through Attribution</td><td><strong>Yes</strong></td></tr><tr><td>Local Currency Code</td><td><strong>Yes</strong> You can <a href="./advanced-settings-configuration.html#local-currency">set your local currency</a> in the Branch Dashboard. This results in a more accurate representation of performance.</td></tr></tbody></table><h2 id="how-does-it-work" tabindex="-1">How Does It Work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How Does It Work?&quot;">​</a></h2><ol><li><p>Branch connects with GMP through an API endpoint. This requires account authentication in the Branch Dashboard through Link IDs set up in GMP.</p><ul><li>If you are using GMP as a campaign manager, and a third party for the ad inventory, see <a href="./google-marketing-platform-overview.html#attribution-claim-scenarios">Attribution Claim Scenarios</a> to get additional details.</li></ul></li><li><p>Events are configured to send from Branch to GMP.</p></li><li><p>Once campaigns are launched, users see an ad to download the app.</p></li><li><p>User installs the app and performs in-app events (ex. PURCHASE).</p><ul><li>The Branch SDK captures the app install and downstream events.</li></ul></li><li><p>Branch communicates with GMP through the API endpoint, sending GMP data about the conversion.</p></li><li><p>GMP claims conversions by sending the click or impression campaign data that sourced it to Branch.</p></li><li><p>The Branch Dashboard will update reports for you to be able to compare and measure ad campaigns across platforms, secondary publishers, etc.</p></li></ol><p>Please note that if you are not using Branch Links, you can only see the <a href="./google-marketing-platform-overview.html#data-mapping">fields provided by GMP</a>.</p><h3 id="attribution-claim-scenarios" tabindex="-1">Attribution Claim Scenarios <a class="header-anchor" href="#attribution-claim-scenarios" aria-label="Permalink to &quot;Attribution Claim Scenarios&quot;">​</a></h3><p>For customers that utilize GMP Ad-server and use trackers on 3rd party platforms (ex. DSPs like The Trade Desk) to get unified reporting in GMP, the attribution claim to Branch will depend on the setup in GMP.</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Details</th></tr></thead><tbody><tr><td>CM360 + Third-Party Media Source</td><td>DoubleClick Manager (DCM) parameters are included in the conversion response, and Branch ingests the DCM parameters. <strong>Attribution conversion credit goes to the third-party media source.</strong> <strong>Note</strong>: To retrieve and see important campaign information in Branch, you must use a Branch Ad Link with the <code>dclid</code> macro added: - If there are existing parameters: <code>&amp;dclid=%edclid!</code> - If there are no existing parameters: <code>?dclid=%edclid!</code></td></tr><tr><td>CM360 + DV360 Media Source</td><td>DoubleClick Bid Manager (DBM) as well as DCM parameters are included in the conversion response, and Branch ingests the parameters. <strong>Attribution conversion credit goes to the DV360 Media Source.</strong></td></tr><tr><td>DV360 Media Source</td><td>DBM + DCM parameters are included (since a CM360 account is created when a DV360 account is created) in the conversion response, and Branch ingests all parameters. <strong>Attribution conversion credit goes to the DV360 Media Source.</strong></td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">Competing Conversion Reporting</p><p>Branch does not recommend enabling Google Ads alongside a third party partner that also reports on Google Ads traffic.</p><p>This is to avoid conflicts when reporting conversions from the same partner via two different integrations.</p><p>For example, if Google Ads is enabled and CM360 is also utilized to report on Google Ads traffic, conversions might be reported by <strong>both</strong> Google Ads and CM360. In this scenario, CM360 will capture some of the conversions that would have been claimed by the main Google Ads integration.</p></div><h3 id="attribution-coverage" tabindex="-1">Attribution Coverage <a class="header-anchor" href="#attribution-coverage" aria-label="Permalink to &quot;Attribution Coverage&quot;">​</a></h3><p>GMP covers attribution under the following properties/conditions:</p><table tabindex="0"><thead><tr><th><strong>Scenario</strong></th><th>Covered</th><th>Not Covered</th></tr></thead><tbody><tr><td>App to App</td><td>Both <strong>click</strong> &amp; <strong>view-through</strong> <strong>conversions</strong>, using device ID.</td><td></td></tr><tr><td>Web to App</td><td>Only <strong>click-through conversions</strong>, using: - dclid for DV360 Supply. - gclid for Google Ads/AdMob supply.</td><td>- View-through conversions - iOS scenarios where users have opted-out via ATT - Non-Google inventory (not leveraging gclid/dclid)</td></tr></tbody></table><h2 id="integrate-gmp-and-branch" tabindex="-1">Integrate GMP and Branch <a class="header-anchor" href="#integrate-gmp-and-branch" aria-label="Permalink to &quot;Integrate GMP and Branch&quot;">​</a></h2><p>Follow the steps below to start tracking conversion events from GMP Ads.</p><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><p>Before you can track conversion events from GMP Ads, you first need to:</p><ul><li><p>Integrate the <a href="./native-sdks-overview.html">Branch SDK</a> into your app.</p><ul><li>If you are using a server-to-server (S2S) integration, make sure the advertising IDs are being passed to Branch.</li></ul></li><li><p>Check with your Google representative for a guide provided by their team to <strong>configure Branch as an App Analytics Partner</strong> and <strong>generate a link ID</strong> for the iOS and Android versions of your app.</p></li></ul><h3 id="enable-gmp-in-branch" tabindex="-1">Enable GMP in Branch <a class="header-anchor" href="#enable-gmp-in-branch" aria-label="Permalink to &quot;Enable GMP in Branch&quot;">​</a></h3><p>To start sending app conversions to GMP for attribution:</p><ol><li>Navigate to the Partner Management <a href="https://branch.dashboard.branch.io/ads/partner-management/a_google_marketing_platform" target="_blank" rel="noreferrer">tab</a> and search for <strong>Google Marketing Platform</strong>.</li><li>Provide the <strong>Link IDs</strong> for your respective apps.</li><li>Click the <strong>Save</strong> button.</li></ol><h3 id="create-gmp-ads-campaign" tabindex="-1">Create GMP Ads Campaign <a class="header-anchor" href="#create-gmp-ads-campaign" aria-label="Permalink to &quot;Create GMP Ads Campaign&quot;">​</a></h3><p>Please follow Google&#39;s documentation on how to set up a <a href="https://support.google.com/dcm/answer/2838056?visit_id=636933638406934064-1262523168&amp;ref_topic=2834022&amp;rd=1" target="_blank" rel="noreferrer">Campaign</a>.</p><h3 id="forward-events-to-gmp" tabindex="-1">Forward Events to GMP <a class="header-anchor" href="#forward-events-to-gmp" aria-label="Permalink to &quot;Forward Events to GMP&quot;">​</a></h3><p>Once you begin <a href="./track-branch-events.html">tracking events</a> with the Branch SDK, Branch will start sending them to GMP.</p><p>Branch will forward in-app events to GMP for campaign optimization. Additionally, Branch will receive attribution data from GMP, resulting in richer analysis in the Branch Dashboard.</p><p>View the Appendix section in this guide for <a href="./google-marketing-platform-overview.html#event-mapping">event mappings</a>.</p><h4 id="custom-events" tabindex="-1">Custom Events <a class="header-anchor" href="#custom-events" aria-label="Permalink to &quot;Custom Events&quot;">​</a></h4><p>GMP supports up to 10 <a href="./track-branch-events.html#track-custom-events">custom events</a> in the following format:</p><ul><li><code>custom</code></li><li><code>custom_1</code></li><li><code>custom_2</code></li><li><code>custom_3</code></li><li><code>custom_4</code></li><li><code>custom_5</code></li><li><code>custom_6</code></li><li><code>custom_7</code></li><li><code>custom_8</code></li><li><code>custom_9</code></li></ul><p>When creating these custom events, you must click the <strong>pencil icon</strong> in order to create the new event.</p><h2 id="appendix" tabindex="-1">Appendix <a class="header-anchor" href="#appendix" aria-label="Permalink to &quot;Appendix&quot;">​</a></h2><h3 id="data-mapping" tabindex="-1">Data Mapping <a class="header-anchor" href="#data-mapping" aria-label="Permalink to &quot;Data Mapping&quot;">​</a></h3><p>Branch maps the following data fields from GMP to Branch.</p><table tabindex="0"><thead><tr><th>GMP</th><th>Branch</th><th>Possible Values</th></tr></thead><tbody><tr><td>n/a</td><td><code>~advertising_partner_name</code></td><td>“Google Marketing Platform”</td></tr><tr><td><code>product_type</code></td><td><code>~channel</code></td><td>This field reports the product that is responsible for the conversions, either “DBM” or “DCM”.</td></tr><tr><td><code>creative_id</code></td><td><code>~creative_id</code></td><td>The numeric ID of the creative ad unit that produced the ad event. This value is guaranteed unique. When product is DBM, this field represents the DBM Creative ID. When product is DCM, this field represents the DCM Creative ID.</td></tr><tr><td><code>placement_id</code></td><td><code>~secondary_publisher</code></td><td>The ID of the placement tag that calls an ad server for ad content when users visit a site. DCM serves ads when users visit a site with DCM placement tags. DCM generates a unique tag for each placement in an ad campaign. This value is only provided when product is DCM.</td></tr><tr><td><code>placement_name</code></td><td><code>~placement</code></td><td>The name of the placement tag that calls an ad server for ad content when users visit a site. DCM serves ads when users visit a site with DCM placement tags. DCM generates a unique tag for each placement in an ad campaign. This value is only provided when product is DCM.</td></tr><tr><td><code>line_item_id</code></td><td><code>~ad_id</code></td><td>Line items in DBM can be used for targeting, bidding and assigning creatives. This is the ID of the line item that produced the ad event. This value is guaranteed unique within the DBM universe. This value is only provided when product is DBM</td></tr><tr><td><code>line_item_name</code></td><td><code>~ad_name</code></td><td>Name of the line items in DBM that produced the ad event. This value is only provided when product is DBM.</td></tr></tbody></table><h3 id="event-mapping" tabindex="-1">Event Mapping <a class="header-anchor" href="#event-mapping" aria-label="Permalink to &quot;Event Mapping&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Branch Event Name</th><th>GMP Conversion Type</th></tr></thead><tbody><tr><td><code>INSTALL</code></td><td><code>FIRST_OPEN</code></td></tr><tr><td><code>PURCHASE</code></td><td><code>ECOMMERCE_PURCHASE</code></td></tr><tr><td><code>INITIATE_PURCHASE</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>ADD_TO_CART</code></td><td><code>ADD_TO_CART</code></td></tr><tr><td><code>VIEW_ITEM</code></td><td><code>VIEW_ITEM</code></td></tr><tr><td><code>VIEW_ITEMS</code></td><td><code>VIEW_ITEM_LIST</code></td></tr><tr><td><code>ADD_PAYMENT_INFO</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>COMPLETE_REGISTRATION</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>SEARCH</code></td><td><code>VIEW_SEARCH_RESULTS</code></td></tr><tr><td><code>ACHIEVE_LEVEL</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>OPEN</code></td><td><code>SESSION_START</code></td></tr><tr><td><code>REINSTALL</code></td><td><code>REINSTALL_OPEN</code></td></tr><tr><td><code>COMPLETE_TUTORIAL</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>ADD_TO_WISHLIST</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>UNLOCK_ACHIEVEMENT</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>SHARE</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>SPEND_CREDITS</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>RATE</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>UPDATE</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>RESERVE</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>LOGIN</code></td><td><code>CUSTOM</code></td></tr><tr><td><code>INVITE</code></td><td><code>CUSTOM</code></td></tr></tbody></table>',44)])])}const g=t(d,[["render",i]]);export{u as __pageData,g as default};
